usbh_status USBH_VS_SetCur(usbh_host *phost, uint16_t request_type)
{
  uint16_t wLength = 26;
  
  
  if (request_type == (VS_PROBE_CONTROL << 8))
  {   
    memset(&ProbeParams, 0, sizeof(ProbeParams));
    // Set needed params, at commit stage this parameters must be receied during "GET_CUR"
    ProbeParams.bmHint = 1;
    ProbeParams.bFormatIndex = USBH_VIDEO_Best_bFormatIndex;             
    ProbeParams.bFrameIndex = USBH_VIDEO_Best_bFrameIndex;
    
    //Maximum framerate can be selected here
   // ProbeParams.dwFrameInterval = 333333;//30 FPS
    //ProbeParams.dwFrameInterval = 2000000;//5 FPS
      ProbeParams.dwFrameInterval = 1000000;//10 FPS
     // ProbeParams.dwFrameInterval = 500000;//20 FPS
     //ProbeParams.dwFrameInterval = 666666;//15 FPS
    //ProbeParams.dwFrameInterval = 400000;//25 FPS
  }

  
  //H2D - host to device
  phost->control.setup.req.bmRequestType = USB_H2D | USB_REQ_RECIPIENT_INTERFACE | \
  USB_REQ_TYPE_CLASS;
  
  VIDEO_HandleTypeDef *VIDEO_Handle;
  VIDEO_Handle =  (VIDEO_HandleTypeDef *) phost->active_class->class_data;
  
  phost->control.setup.req.bRequest = UVC_SET_CUR;
  phost->control.setup.req.wValue = request_type;
  phost->control.setup.req.wIndex = VIDEO_Handle->camera.interface; //Video Streaming interface number
  phost->control.setup.req.wLength = wLength;
  
  
    usbh_status status = USBH_BUSY;

    usbh_control *usb_ctl = &phost->control;

    if (CTL_IDLE == usb_ctl->ctl_state) {
        usb_ctl->setup.req = (usb_req) {
            .bmRequestType = 0x21,    //0x21  USB_TRX_OUT | USB_RECPTYPE_DEV | USB_REQTYPE_STRD
            .bRequest      = UVC_SET_CUR,                                 //0x01
            .wValue        = request_type,               
            .wIndex        = VIDEO_Handle->camera.interface,
            .wLength       = wLength
        };
    
        usbh_ctlstate_config (phost, (uint8_t *)&ProbeParams, wLength);    
    }
    
    do
    {
         status = usbh_ctl_handler (phost);
    }while(status == USBH_BUSY);
     
    return status;  
}

usbh_status USBH_VS_GetCur(usbh_host *phost, uint16_t request_type)
{
  memset(&ProbeParams, 0, sizeof(ProbeParams));
  uint16_t wLength = 26;

  //H2D - host to device
  phost->control.setup.req.bmRequestType = USB_D2H | USB_REQ_RECIPIENT_INTERFACE | USB_REQ_TYPE_CLASS ;     //
  
  
  VIDEO_HandleTypeDef *VIDEO_Handle;
  VIDEO_Handle =  (VIDEO_HandleTypeDef *) phost->active_class->class_data;   //phost->active_class->class_data
  
  phost->control.setup.req.bRequest = UVC_GET_CUR;    //0x81
  phost->control.setup.req.wValue = request_type;    //0x0100
  phost->control.setup.req.wIndex = VIDEO_Handle->camera.interface; //Video Streaming interface number  0x01
  phost->control.setup.req.wLength = wLength;   //0x1A
  
    usbh_status status = USBH_BUSY;

    usbh_control *usb_ctl = &phost->control;
  
    if (CTL_IDLE == usb_ctl->ctl_state) {
        usb_ctl->setup.req = (usb_req) {
            .bmRequestType = 0xA1,    //0x21  USB_TRX_OUT | USB_RECPTYPE_DEV | USB_REQTYPE_STRD
            .bRequest      = UVC_GET_CUR,                                 //0x01
            .wValue        = request_type,               
            .wIndex        = VIDEO_Handle->camera.interface,
            .wLength       = wLength
        };
  
        
        usbh_ctlstate_config (phost, (uint8_t *)&ProbeParams, wLength);
    }
      
    do
    {
         status = usbh_ctl_handler (phost);
    }while(status == USBH_BUSY);  
    
  if (status == USBH_OK)
  {
    if (ProbeParams.dwMaxVideoFrameSize > 0)
    {      
      return USBH_OK;
    }
    else
      return USBH_FAIL;
  }
  
  return status;
}


