/*
 * user callbak definition
*/ 
void USBH_UserProcess(usbh_host *phost, uint8_t id)
{
  /* USER CODE BEGIN 2 */
  switch(id)
  { 
  case HOST_USER_CLASS_SELECTED:
    { 
      usbh_status  status;  
      status = USBH_VS_SetCur(phost, VS_PROBE_CONTROL << 8);
      
      status = USBH_VS_GetCur(phost, VS_PROBE_CONTROL << 8);
          
      if (status == USBH_OK)
      {
            USBH_VS_SetCur(phost, VS_COMMIT_CONTROL << 8);
            //USBH_VS_GetCur_test(phost, VS_COMMIT_CONTROL << 8);
    //        status = USBH_VS_GetCur(phost, VS_COMMIT_CONTROL << 8);// not necessary
      }      
    
    }
    break;
    
  case HOST_USER_SELECT_CONFIGURATION:
    break;
    
  case HOST_USER_DISCONNECTION:
    Appli_state = APPLICATION_DISCONNECT;
    break;
    
  case HOST_USER_CLASS_ACTIVE:
    Appli_state = APPLICATION_READY;
    break;
    
  case HOST_USER_CONNECTION:
    Appli_state = APPLICATION_START;
    break;
  case HOST_USER_SET_BACKLIGHT:
    uvc_set_backlight(phost, sys_para.video.backlight_val);
    break;
  case  HOST_USER_SET_GAIN:
    uvc_set_gain(phost, sys_para.video.gain_val);
    break;
  default:
    break; 
  }
  /* USER CODE END 2 */
}

void timer11_handler(void) {
    BaseType_t xHigherPriorityTaskWoken = pdFALSE;
    int result;
    DEFINE_CPU_SR;

    ENTER_ISR();
    if (timer_flag_get(TIMER11, TIMER_FLAG_UP) == SET) {
        result = USBH_VIDEO_Process(&usb_host_uvc);
        
        if (1 == result ){
            xSemaphoreGiveFromISR( xSendSemaphore, &xHigherPriorityTaskWoken );

         if( xHigherPriorityTaskWoken != pdFALSE ){
                    // We can force a context switch here.  Context switching from an
                    // ISR uses port specific syntax.  Check the demo task for your port
                    // to find the syntax required.
                     portYIELD_FROM_ISR( xHigherPriorityTaskWoken );
            }
        }
            timer_flag_clear(TIMER11, TIMER_FLAG_UP); /* ack irq */
        }
    
    EXIT_ISR();
}


